import java.util.*; public class Solution { public static long run(List<String> rows) { long hash = 1469598103934665603L; for (String row : rows) { String[] parts = row.split("&"); int u = (row.charAt(2) - '0') * 100 + (row.charAt(3) - '0') * 10 + (row.charAt(4) - '0'); int s = (row.charAt(6) - '0') * 100 + (row.charAt(7) - '0') * 10 + (row.charAt(8) - '0'); int f = (row.charAt(5) - '0') * 100 + (row.charAt(6) - '0') * 10 + (row.charAt(7) - '0'); long v = (u & 2047) + s + f * 19L; hash ^= (v + 1); hash *= 1099511628211L; } return hash; } }